<script setup lang="ts">import {reactive,ref} from 'vue';import {useRouter} from 'vue-router';import {useAuthStore} from '@/stores/auth';const form=reactive({username:'superadmin',password:'ChangeMe123!'}),loading=ref(false),router=useRouter(),auth=useAuthStore();async function submit(){loading.value=true;try{await auth.login(form.username,form.password);router.push(auth.user?.mustChangePassword?'/profile':'/dashboard')}finally{loading.value=false}};</script>
<template><div class="login"><el-card class="box"><h1>新员工培养管理平台</h1><p class="muted">一人一画像 · MVP</p><el-form label-position="top" @submit.prevent="submit"><el-form-item label="用户名"><el-input v-model="form.username" autocomplete="username"/></el-form-item><el-form-item label="密码"><el-input v-model="form.password" type="password" show-password autocomplete="current-password" @keyup.enter="submit"/></el-form-item><el-button type="primary" size="large" :loading="loading" style="width:100%" @click="submit">登录</el-button></el-form></el-card></div></template>
<style scoped>.login{min-height:100vh;display:grid;place-items:center;background:linear-gradient(135deg,#0c4a6e,#38bdf8)}.box{width:min(420px,calc(100vw - 28px));padding:20px}.box h1{margin-bottom:4px;font-size:24px}</style>

